import React, {useState} from 'react';
import auth from '../services/auth';

const Login = ()=>{
  const [email,setEmail] = useState('');
  const [password,setPassword] = useState('');
  const [loading,setLoading] = useState(false);
  const [error,setError] = useState('');

  const submit = async (e)=>{
    e.preventDefault();setLoading(true);setError('');
    const res = await auth.login(email,password);
    setLoading(false);
    if(res.ok){
      window.location.href = '/';
    }else{
      setError(res.message || 'Login failed');
    }
  }

  return (
    <div style={{padding:40}}>
      <div className="login-panel">
        <h3>Admin Login</h3>
        <p className="small-muted">Authorized Administrators Only</p>
        <form onSubmit={submit} style={{marginTop:18,display:'grid',gap:12}}>
          <input className="input" placeholder="Email" value={email} onChange={e=>setEmail(e.target.value)} />
          <input className="input" type="password" placeholder="Password" value={password} onChange={e=>setPassword(e.target.value)} />
          <div style={{display:'flex',justifyContent:'space-between',alignItems:'center'}}>
            <button className="btn" disabled={loading}>{loading? 'Signing in...':'Login'}</button>
            <div style={{color:'var(--muted)',fontSize:12}}>Forgot password? Ask system admin</div>
          </div>
        </form>
        {error && <div style={{color:'var(--danger)',marginTop:12}}>{error}</div>}

        <div style={{marginTop:16}}>
          <strong>Demo Admin:</strong>
          <div className="small-muted">email: admin@harari.test — password: Admin123!</div>
        </div>
      </div>
    </div>
  );
}
export default Login;
